// Hər dil üçün hədis massivi qur
function buildForLang(l) {
  return RAW.map(h => ({
    id:     h.id,
    cat:    h.cat,
    source: h.source,
    ar:     h.ar,
    text:   h[l] || h.en,
  }))
}

export const HADITHS = {
  az: buildForLang('az'),
  en: buildForLang('en'),
  ru: buildForLang('ru'),
  tr: buildForLang('tr'),
  ar: buildForLang('ar'),
}